CREATE OR REPLACE FUNCTION public.get_top_copilot_actions(_user_id uuid, _context_type text, _context_subtype text DEFAULT NULL, _limit int DEFAULT 5) RETURNS TABLE(action_key text, action_label text, click_count bigint, last_clicked timestamptz) LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public AS $fn$ SELECT action_key, (array_agg(action_label ORDER BY created_at DESC))[1], count(*), max(created_at) FROM public.copilot_button_clicks WHERE user_id = _user_id AND context_type = _context_type AND (_context_subtype IS NULL OR context_subtype = _context_subtype) AND created_at > now() - interval '90 days' GROUP BY action_key ORDER BY count(*) DESC, max(created_at) DESC LIMIT _limit $fn$;